 77→                PostListItemViewHolder.Compact(parent, imageManager, uiHelpers)
 78→            }
 79→            else -> {
 80→                // Fail fast if a new view type is added so the we can handle it
 81→                throw IllegalStateException("The view type '$viewType' needs to be handled")
 82→            }
 83→        }
 84→    }
 85→
 86→    override fun onBindViewHolder(holder: ViewHolder, position: Int) {
 87→        // The only holders that require special setup are PostListItemViewHolder and LoadingViewHolder subclasses
 88→        if (holder is PostListItemViewHolder) {
 89→            val item = getItem(position)
 90→            assert(item is PostListItemUiState) {
 91→                "If we are presenting PostViewHolder, the item has to be of type PostListItemUiState " +
 92→                        "for position: $position"
 93→            }
 94→            holder.onBind((item as PostListItemUiState))
 95→        }
 96→        if (holder is LoadingViewHolder) {
 97→            val item = getItem(position)
 98→            assert(item is LoadingItem?) {
 99→                "If we are presenting LoadingViewHolder, the item has to be of type LoadingItem " +
100→                        "for position: $position"
101→            }
102→            // getItem returns the item, or NULL, if a null placeholder is at the specified position.
103→            item?.let { holder.onBind((item as LoadingItem)) }
104→        }
105→    }
106→
107→    fun updateItemLayoutType(updatedItemLayoutType: PostListViewLayoutType): Boolean {
108→        if (updatedItemLayoutType == itemLayoutType) {
109→            return false
110→        }
111→        itemLayoutType = updatedItemLayoutType
112→        notifyDataSetChanged()
113→        return true
114→    }
115→
116→    private class LoadingViewHolder(view: View) : ViewHolder(view) {
117→        val editButton: View? = view.findViewById(R.id.skeleton_button_edit)
118→        val viewButton: View? = view.findViewById(R.id.skeleton_button_view)
119→        val buttonMore: View? = view.findViewById(R.id.skeleton_button_more)
120→        val buttonMoveToDraft: View? = view.findViewById(R.id.skeleton_button_move_to_draft)
121→        val buttonDeletePermanently: View? = view.findViewById(R.id.skeleton_button_delete_permanently)
122→
123→        fun onBind(item: LoadingItem) {
124→            editButton?.setVisible(item.options.showEditButton)
125→            viewButton?.setVisible(item.options.showViewButton)
126→            buttonMore?.setVisible(item.options.showMoreButton)
127→            buttonMoveToDraft?.setVisible(item.options.showMoveToDraftButton)
128→            buttonDeletePermanently?.setVisible(item.options.showDeletePermanentlyButton)
129→        }
130→    }
131→
132→    private class EndListViewHolder(view: View) : ViewHolder(view)
133→}
134→
135→private val PostListDiffItemCallback = object : DiffUtil.ItemCallback<PostListItemType>() {
136→    override fun areItemsTheSame(oldItem: PostListItemType, newItem: PostListItemType): Boolean {
137→        if (oldItem is EndListIndicatorItem && newItem is EndListIndicatorItem) {
138→            return true
139→        }
140→        if (oldItem is LoadingItem && newItem is LoadingItem) {
141→            return oldItem.localOrRemoteId == newItem.localOrRemoteId
142→        }
143→        if (oldItem is PostListItemUiState && newItem is PostListItemUiState) {
144→            return oldItem.data.localPostId == newItem.data.localPostId
145→        }
146→        if (oldItem is LoadingItem && newItem is PostListItemUiState) {
147→            return when (oldItem.localOrRemoteId) {
148→                is LocalId -> oldItem.localOrRemoteId == newItem.data.localPostId.id
149→                is RemoteId -> oldItem.localOrRemoteId == newItem.data.remotePostId.id
150→            }
151→        }
152→        return false
153→    }
154→
155→    override fun areContentsTheSame(oldItem: PostListItemType, newItem: PostListItemType): Boolean {
156→        if (oldItem is EndListIndicatorItem && newItem is EndListIndicatorItem) {
157→            return true
158→        }
159→        if (oldItem is LoadingItem && newItem is LoadingItem) {
160→            return when (oldItem.localOrRemoteId) {
161→                is LocalId -> oldItem.localOrRemoteId.value == (newItem.localOrRemoteId as? LocalId)?.value
162→                is RemoteId -> oldItem.localOrRemoteId.value == (newItem.localOrRemoteId as? RemoteId)?.value
163→            }
164→        }
165→        if (oldItem is PostListItemUiState && newItem is PostListItemUiState) {
166→            return oldItem.data == newItem.data
167→        }
168→        return false
169→    }
170→
171→    override fun getChangePayload(oldItem: PostListItemType, newItem: PostListItemType): Any? {
172→        if (oldItem is PostListItemUiState && newItem is PostListItemUiState) {
173→            /**
174→             * Suppresses the default animation if the progress has changed to prevent blinking as the upload progresses
175→             *
176→             * We don't need to use the payload in onBindViewHolder unless we want to. Passing a non-null value
177→             * suppresses the default ItemAnimator, which is all we need in this case.
178→             */
179→            if (oldItem.data.progressBarUiState is ProgressBarUiState.Determinate &&
180→                newItem.data.progressBarUiState is ProgressBarUiState.Determinate &&
181→                oldItem.data.progressBarUiState.progress != newItem.data.progressBarUiState.progress
182→            ) {
183→                return true
184→            }
185→        }
186→        return super.getChangePayload(oldItem, newItem)
187→    }
188→}
